        // Simple paragraph converts to plain text
        val result = dev.kreuzberg.android.HtmlToMarkdownRs.convert("<p>Hello World</p>", ConversionOptions())
        assertEquals("Hello World", result.content.orEmpty().trim())
    }

    @Test
    fun testParagraphWithInlineFormatting() = runBlocking {
        // Paragraph with bold, italic, and a link
        val result = dev.kreuzberg.android.HtmlToMarkdownRs.convert("<p>This has <strong>bold</strong>, <em>italic</em>, and a <a href=\"https://example.com\">link</a>.</p>", ConversionOptions())
        assertTrue(result.content.orEmpty().contains("**bold**"), "expected to contain: " + "**bold**")
        assertTrue(result.content.orEmpty().contains("*italic*"), "expected to contain: " + "*italic*")
        assertTrue(result.content.orEmpty().contains("[link](https://example.com)"), "expected to contain: " + "[link](https://example.com)")
    }

    @Test
    fun testParagraphWithLineBreaks() = runBlocking {
        // Paragraph with br tags produces line breaks in output
        val result = dev.kreuzberg.android.HtmlToMarkdownRs.convert("<p>Line one.<br>Line two.<br>Line three.</p>", ConversionOptions())
        assertTrue(result.content != null, "expected non-empty value")
        assertTrue(result.content.orEmpty().contains("Line one."), "expected to contain: " + "Line one.")
        assertTrue(result.content.orEmpty().contains("Line two."), "expected to contain: " + "Line two.")
        assertTrue(result.content.orEmpty().contains("Line three."), "expected to contain: " + "Line three.")
    }

