    @Test
    fun testSemanticSubSuperscript() = runBlocking {
        // Subscript and superscript elements are preserved in output
        val result = dev.kreuzberg.android.HtmlToMarkdownRs.convert("<p>H<sub>2</sub>O and E=mc<sup>2</sup></p>", ConversionOptions())
        assertTrue(result.content != null, "expected non-empty value")
        assertTrue(result.content.orEmpty().contains("H"), "expected to contain: " + "H")
        assertTrue(result.content.orEmpty().contains("2"), "expected to contain: " + "2")
        assertTrue(result.content.orEmpty().contains("O"), "expected to contain: " + "O")
        assertTrue(result.content.orEmpty().contains("E=mc"), "expected to contain: " + "E=mc")
    }

    @Test
