        assertTrue(result.content.orEmpty().contains("Product"), "expected to contain: " + "Product")
        assertTrue(result.content.orEmpty().contains("Price"), "expected to contain: " + "Price")
        assertTrue(result.content.orEmpty().contains("Apple"), "expected to contain: " + "Apple")
        assertTrue(result.content.orEmpty().contains("1.00"), "expected to contain: " + "1.00")
        assertTrue(result.content.orEmpty().contains("|"), "expected to contain: " + "|")
    }

    @Test
